import{_ as r,c as t,o as s,ag as n}from"./chunks/framework.DVUBUV_u.js";const d=JSON.parse('{"title":"Чёрный список","description":"","frontmatter":{"title":"Чёрный список"},"headers":[],"relativePath":"props/blacklist.md","filePath":"props/blacklist.md"}'),a={name:"props/blacklist.md"};function e(g,o,l,i,p,h){return s(),t("div",null,[...o[0]||(o[0]=[n('<h1 id="черныи-список-компонентов-props" tabindex="-1">Чёрный список компонентов (Props) <a class="header-anchor" href="#черныи-список-компонентов-props" aria-label="Permalink to &quot;Чёрный список компонентов (Props)&quot;">​</a></h1><p><strong>Чёрный список</strong> в контексте вкладки <strong>Props</strong> — это набор <strong>имён компонентов Vue</strong>, которые при сборе дерева <strong>не показываются</strong> в таблице инспектора. Фильтрация выполняется <strong>на стороне страницы</strong>, до тяжёлого чтения props: такие инстансы не попадают в список и не тратят ресурсы на сериализацию.</p><p>Общее описание вкладки Props: <a href="/docs/props/general.html">Основные возможности</a>.</p><p>Не путайте с <strong>чёрным списком сайтов</strong> для <strong>автозапуска</strong> оверлея (отдельная логика по URL страницы в настройках <strong>General / Auto Run</strong>). Здесь речь только об <strong>именах компонентов</strong>.</p><hr><h2 id="где-настраивать" tabindex="-1">Где настраивать <a class="header-anchor" href="#где-настраивать" aria-label="Permalink to &quot;Где настраивать&quot;">​</a></h2><p>Секция <strong>Component Blacklist</strong> находится в <strong>Options</strong> инспектора рядом с настройками поиска по Props и режимом Inspect (в приложении это вкладка настроек, блок <strong>Props</strong>). Там же задаётся список правил, их включение и исключения.</p><p>Дополнительно имя можно добавить в чёрный список <strong>из таблицы Props</strong> через действие вроде «игнорировать по имени» у строки (точное имя текущего компонента попадает в активный список, если его ещё не было).</p><hr><h2 id="активные-и-неактивные-правила" tabindex="-1">Активные и неактивные правила <a class="header-anchor" href="#активные-и-неактивные-правила" aria-label="Permalink to &quot;Активные и неактивные правила&quot;">​</a></h2><p>Список разделён на два набора строк:</p><ul><li><strong>Активные</strong> (<strong>Blocked</strong>) — правило <strong>действует</strong>: совпавшие по имени компоненты <strong>скрыты</strong> из дерева.</li><li><strong>Неактивные</strong> (<strong>Off</strong> / переведённые действием «разрешить») — строка хранится, но <strong>не блокирует</strong>. Её можно снова включить («заблокировать») без повторного ввода имени.</li></ul><p>Удаление строки полностью убирает правило из обоих наборов.</p><p>Пока в <strong>активном</strong> списке нет ни одного правила, фильтрация по чёрному списку фактически <strong>выключена</strong> (строки только среди неактивных используются после следующего включения).</p><hr><h2 id="как-сопоставляется-имя" tabindex="-1">Как сопоставляется имя <a class="header-anchor" href="#как-сопоставляется-имя" aria-label="Permalink to &quot;Как сопоставляется имя&quot;">​</a></h2><p>Сравнение идёт с <strong>именем компонента</strong> так, как его видит инспектор (в т.ч. для безымянных экземпляров может использоваться запасной ярлык вроде <strong>Anonymous</strong> на стороне кода).</p><ul><li>Если в правиле <strong>нет</strong> символов <strong><code>*</code></strong> и <strong><code>%</code></strong>, имя должно совпасть <strong>буквально</strong> (без учёта регистра): например правило <code>MyButton</code> скрывает только компоненты с таким именем.</li><li>Символы <strong><code>*</code></strong> и <strong><code>%</code></strong> в правиле трактуются как <strong>подстановка произвольного фрагмента</strong> (по смыслу «начинается / содержит / маска» в одном шаблоне, оформленном как одна строка с подстановками). Так можно задать, например, общий префикс для целого семейства компонентов.</li></ul><p>Если имя компонента совпало с <strong>неактивным</strong> правилом‑исключением, оно <strong>не считается</strong> заблокированным, даже если подходит под другое активное правило (исключение проверяется первым). Это удобно, чтобы временно «пропустить» узкий поднабор имён внутри широкой маски.</p><hr><h2 id="когда-применяется" tabindex="-1">Когда применяется <a class="header-anchor" href="#когда-применяется" aria-label="Permalink to &quot;Когда применяется&quot;">​</a></h2><p>При каждом запросе списка компонентов (<strong>Refresh</strong>, автообновление, первое открытие) на страницу передаётся актуальный чёрный список вместе с запросом. После <strong>изменения</strong> правил в настройках дерево Props обычно <strong>перезапрашивается</strong>, чтобы таблица сразу отражала новый набор.</p><p>Заблокированные компоненты <strong>исчезают</strong> из основного списка: их нельзя выбрать карточкой, пока правило активно (если только не снять блок или не ослабить шаблон).</p><hr><h2 id="практические-советы" tabindex="-1">Практические советы <a class="header-anchor" href="#практические-советы" aria-label="Permalink to &quot;Практические советы&quot;">​</a></h2><ul><li>Начинайте с <strong>точных имён</strong> из таблицы, если нужно убрать шум от одного известного компонента.</li><li><strong>Широкие маски</strong> экономят время, но легко скрыть лишнее — используйте <strong>неактивные исключения</strong> или уточняйте шаблон.</li><li>Чёрный список <strong>не удаляет</strong> компонент из приложения Vue; он влияет только на <strong>отображение</strong> в Vue Inspector.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/props/general.html">Основные возможности Props</a></li><li><a href="/docs/props/inspect.html">Инспектор (выбор на странице)</a></li><li><a href="/docs/options/customize.html">Персонализация / настройки</a></li></ul>',29)])])}const u=r(a,[["render",e]]);export{d as __pageData,u as default};
